/* ── Recruiter Banner ── */
@media print { #recruiter-banner, #banner-spacer { display: none !important; } }

#recruiter-banner {
    position: fixed;
    top: 0; left: 0; right: 0;
    z-index: 50;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

/* Collapsed bar */
#banner-bar {
    background: rgba(255,255,255,0.9);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    border-bottom: 1px solid #e5e7eb;
}
#banner-btn {
    width: 100%; height: 44px;
    display: flex; align-items: center; justify-content: center;
    background: transparent; border: none; cursor: pointer;
    padding: 0; font-family: inherit;
    transition: background 0.15s;
}
#banner-btn:hover { background: rgba(249,250,251,0.8); }
#banner-btn-inner {
    display: flex; align-items: center; gap: 6px;
    font-size: 13px; letter-spacing: 0.025em;
    color: #4b5563; font-weight: normal;
    transition: color 0.15s;
}
#banner-btn:hover #banner-btn-inner { color: #111827; }
#banner-arrow {
    display: inline-block; font-style: normal;
    color: #9ca3af; line-height: 1;
    transform-origin: center;
    transition: transform 0.15s ease, color 0.15s;
}
#banner-btn:hover #banner-arrow { color: #8b5cf6; }
#banner-arrow.open { transform: rotate(90deg); }
#banner-label { font-weight: 500; }

/* Expanded panel */
#banner-panel {
    background: #fff;
    border-bottom: 1px solid #e5e7eb;
    box-shadow: 0 1px 2px rgba(0,0,0,0.05);
    max-height: 0; overflow: hidden; opacity: 0;
    transition: max-height 0.18s cubic-bezier(0.22,1,0.36,1),
                opacity 0.18s cubic-bezier(0.22,1,0.36,1);
}
#banner-panel.open { max-height: 40vh; opacity: 1; }

#banner-inner {
    max-width: 896px; margin: 0 auto;
    padding: 20px 24px;
    display: flex; flex-direction: column; gap: 16px;
    min-height: 280px; max-height: 40vh;
    box-sizing: border-box;
}

/* Controls row */
#banner-controls {
    display: flex; align-items: center;
    justify-content: space-between; gap: 12px;
    flex-wrap: wrap; flex-shrink: 0;
}
#banner-hint-text { font-size: 14px; color: #4b5563; margin: 0; }
#banner-controls-right { display: flex; align-items: center; gap: 8px; }

/* Language pill group */
#banner-lang-toggle {
    display: flex; gap: 2px;
    background: #f3f4f6; border-radius: 6px; padding: 2px;
}
.blang-btn {
    padding: 4px 12px; border-radius: 4px;
    font-size: 12px; font-weight: 500; color: #6b7280;
    background: transparent; border: none; cursor: pointer;
    font-family: inherit;
    transition: background 0.1s, color 0.1s, box-shadow 0.1s;
}
.blang-btn:hover { color: #374151; }
.blang-btn.active { background: #fff; color: #111827; box-shadow: 0 1px 2px rgba(0,0,0,0.08); }

/* Copy button */
#banner-copy-btn {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 12px;
    background: #111827; color: #fff;
    border: none; border-radius: 6px;
    font-size: 12px; font-weight: 500; cursor: pointer;
    font-family: inherit;
    transition: background 0.15s, transform 0.1s;
}
#banner-copy-btn:hover { background: #1f2937; }
#banner-copy-btn:active { transform: scale(0.96); }

/* Close button */
#banner-close-btn {
    padding: 6px; background: transparent; border: none;
    cursor: pointer; border-radius: 6px;
    color: #6b7280; line-height: 1; font-size: 16px;
    font-family: inherit;
    transition: background 0.12s;
}
#banner-close-btn:hover { background: #f3f4f6; }

/* Prompt area */
#banner-prompt-area {
    flex: 1; overflow-y: auto;
    background: #f9fafb; border-radius: 6px;
    padding: 16px; border: 1px solid #e5e7eb;
}
#banner-prompt-pre {
    font-size: 12px;
    font-family: 'SF Mono', 'Fira Code', 'Courier New', monospace;
    color: #374151; line-height: 1.625;
    white-space: pre-wrap; margin: 0;
    transition: opacity 0.12s;
}

#banner-spacer { height: 44px; transition: height 0.18s cubic-bezier(0.22,1,0.36,1); }

